// ── Record types (UDL `dictionary` mapping) ───────────────────────────────────

// In the UDL workflow, scaffolding generated by build.rs already applies the
// udl_derive(Record) attribute; adding #[derive(uniffi::Record)] here would
// duplicate trait impls and cause E0119.  Plain derives only.
#[derive(Debug, Clone)]
pub struct ArchiveEntryRecord {
    pub index: u32,
    pub filename: String,
    pub size_bytes: u64,
}

#[derive(Debug, Clone)]
pub struct SessionStateRecord {
    pub page_index: u32,
    pub zoom_level: f64,
    pub rotation_degrees: i32,
    pub two_page_spread: bool,
    pub right_to_left: bool,
    pub scale_mode: i32,
    pub scroll_x: f64,
    pub scroll_y: f64,
}

#[derive(Debug, Clone)]
